function calculerPrixFinal(prix, modePaiement) {
  let reduction = 0;
  if (modePaiement === 'MTN' || modePaiement === 'Orange') {
    reduction = 0.05;
  } else if (modePaiement === 'Visa' || modePaiement === 'Mastercard') {
    reduction = 0.10;
  } else {
    reduction = 0;
  }
  return prix * (1 - reduction);
}
```

