function estValide(mdp) {
  if (mdp.length < 8) {
    return false;
  }
  let aUnChiffre = false;
  for (let i = 0; i < mdp.length; i++) {
    if (!isNaN(parseInt(mdp[i]))) {
      aUnChiffre = true;
      break;
    }
  }
  return aUnChiffre;
}
```

